var countAndSay = function(n) {
    let s = '1';
    for (let k = 1; k < n; k++) {
        let out = '';
        let i = 0;
        while (i < s.length) {
            let j = i;
            while (j < s.length && s[j] === s[i]) j++;
            out += String(j - i) + s[i];
            i = j;
        }
        s = out;
    }
    return s;
